import { createContext, useContext, useEffect, useState } from 'react';

const AuthContext = createContext(null);

const getUserFromStorage = () => {
  try {
    return JSON.parse(localStorage.getItem('erp-user')) || null;
  } catch {
    return null;
  }
};

export function AuthProvider({ children }) {
  const [user, setUser] = useState(getUserFromStorage());

  useEffect(() => {
    localStorage.setItem('erp-user', JSON.stringify(user));
  }, [user]);

  const login = (username) => {
    const sanitized = username.trim();
    if (!sanitized) throw new Error('Nom utilisateur requis');
    setUser({ name: sanitized });
  };

  const logout = () => {
    setUser(null);
    localStorage.removeItem('erp-user');
  };

  return (
    <AuthContext.Provider value={{ user, login, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const auth = useContext(AuthContext);
  if (!auth) throw new Error('useAuth doit être utilisé sous AuthProvider');
  return auth;
}
